#include <stdio.h>
#include "riscv_nn_activation.h"
#include "test_util.h"
#ifdef PF_COUNTER
#include "nds_pfcounter.h"
#endif

int test(char* fname_in,
        char* fname_golden,
        uint32_t size,
        float snr_threshold)
{
    {
        dump_param("size=%" PRIu32, size);
    }

    FILE *fptr_in, *fptr_golden;
    //backup originally malloced starting address for later memory releasing
    void *in_ori, *out_ori, *golden_ori;

    float32_t *in = (float32_t*)test_malloc(sizeof(float32_t) * size, "in", &in_ori);
    float32_t *out = (float32_t*)test_malloc(sizeof(float32_t) * size, "out", &out_ori);
    float32_t *golden = (float32_t*)test_malloc(sizeof(float32_t) * size, "golden", &golden_ori);

    test_Fopen(fname_in, "rb", &fptr_in);
    test_Fread(in, sizeof(*in), size, fptr_in, "in");
    process_after_reading_input_data();

#ifdef ENA_RUN_TWICE
    riscv_nn_gelu_f32(in, size, out);
#endif

    process_before_perf_measuring();
#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_gelu_f32(in, size, out);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if ENA_DUMP_GOLDEN
    test_Fopen(fname_golden, "wb+", &fptr_golden);
    fwrite(out, sizeof(*golden), size, fptr_golden);
    uint32_t retStatus = NDS_SUCCESS;
#else
    test_Fopen(fname_golden, "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), size, fptr_golden, "golden");
    uint32_t retStatus = verify_buffer_f32(out, golden, size, snr_threshold);
#endif

    test_free(&in_ori);
    test_free(&golden_ori);
    fclose(fptr_in);
    fclose(fptr_golden);

    return retStatus;
}

int main (void)
{
    enable_fs_and_vs();
    uint32_t size;
    float snr_threshold;
    uint32_t retStatus=NDS_SUCCESS;

#if !ENA_MEASURE_PERF
    //test-1
    size = 10;
#if defined(ENA_FAST_ALGO)
    snr_threshold = 56.f;
#else
    snr_threshold = -1.f;
#endif
    retStatus |= test("f32_in_gelu_10.bin", "gelu_f32_golden.bin", size, snr_threshold);

    //test-2
    size = 100;
#if defined(ENA_FAST_ALGO)
    snr_threshold = 56.f;
#else
    snr_threshold = 160.f;
#endif
    retStatus |= test("f32_in_gelu_100.bin", "gelu_f32_golden2.bin", size, snr_threshold);
#endif

    //test-3
    size = 4096;
#if defined(ENA_FAST_ALGO)
    snr_threshold = 54.f;
#else
    snr_threshold = 165.f;
#endif
    retStatus |= test("f32_in_gelu_4096.bin", "gelu_f32_golden3.bin", size, snr_threshold);

    return retStatus;
}

